int dfs(int x, int y) {
  int best = 0;

  // Add the starting‐cell value once, at (0,0)
  if (x==0 && y==0)      
    best += a[0][0];

  // If we have actually reached the bottom‐right cell (1,n−1),
  // we reset best to 0 so that all further additions come
  // from recursive calls rather than re‐adding a[1][n−1].
  if (x==1 && y==n-1)    
    best = 0;   

  // Try to move “down” (x+1,y) and “right” (x,y+1) if they stay in bounds;
  // take the maximum of the two possible continuations.
  boolean canDown  = (x+1 < 2) && (y   < n);
  boolean canRight = (x   < 2) && (y+1 < n);

  if (canDown && canRight) {
    best += Math.max(
             dfs(x+1, y) + a[x+1][y],
             dfs(x, y+1) + a[x][y+1]
           );
  }
  else if (canDown) {
    best += dfs(x+1, y) + a[x+1][y];
  }
  else if (canRight) {
    best += dfs(x, y+1) + a[x][y+1];
  }
  // else we’re at a dead end (only happens at the target), best stays 0

  return best;
}
```

